# -----------------------------
# 1. grades.py calls missing generate_grade_bar
# -----------------------------
@pytest.mark.asyncio
async def test_missing_generate_grade_bar():
    interaction = type("I", (), {})()
    interaction.response = type("R", (), {"defer": lambda *a, **k: None})()
    interaction.followup = type("F", (), {"send": lambda *a, **k: None})()

    cog = grades_cog.GradesCog(bot=None)

    with pytest.raises(AttributeError):
        await cog.grades.callback(cog, interaction, "CS 3114")


