# -----------------------------
# 3. rmp.py parses wrong GraphQL field
# -----------------------------
@pytest.mark.asyncio
async def test_rmp_wrong_graphql_parsing(monkeypatch):
    class FakeResponse:
        status = 200

        async def json(self, content_type=None):
            return {
                "data": {
                    "search": {
                        "teachers": {
                            "edges": [
                                {"node": {
                                    "firstName": "Test",
                                    "lastName": "Prof",
                                    "numRatings": 10
                                }}
                            ]
                        }
                    }
                }
            }

        async def __aenter__(self): return self
        async def __aexit__(self, *args): return False

    class FakeSession:
        def __init__(self, *args, **kwargs):
            pass

        async def __aenter__(self): return self
        async def __aexit__(self, *args): return False
        def post(self, *args, **kwargs): return FakeResponse()

    monkeypatch.setattr(rmp.aiohttp, "ClientSession", FakeSession)

    prof = await rmp.search_professor("Test Prof")

    assert prof is not None


