# -----------------------------
# 9. recommendation payload parsing bug
# -----------------------------
def test_recommendation_payload_bug():
    raw = """
    CS 3214 Systems
    CS 3704 Software Engineering
    Balance workload
    """.strip()

    rows, notes = courses_cog._format_recommendation_payload(raw)

    assert "CS 3214" in rows
    assert "CS 3704" in rows
    assert "Balance" in notes


